/**
 * Build the standalone iframe SDK as a self-contained IIFE.
 * Output: dist/okdoc-iframe-sdk.js + dist/okdoc-iframe-sdk-global.d.ts (auto-generated)
 *
 * Usage: node scripts/build-iframe-sdk.mjs
 */
import { build } from 'esbuild';
import { readFile, writeFile } from 'fs/promises';
import { fileURLToPath } from 'url';
import { dirname, resolve } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));

await build({
    entryPoints: [resolve(__dirname, '../src/iframe-sdk.ts')],
    bundle: true,
    format: 'iife',
    globalName: '_okdocIframeSDK',
    outfile: resolve(__dirname, '../dist/okdoc-iframe-sdk.js'),
    target: 'es2020',
    minify: true,
    sourcemap: false,
    platform: 'browser',
    logLevel: 'info',
});

console.log('✅ okdoc-iframe-sdk.js built successfully');

// ── Auto-generate global type declarations from tsc output ──────────────────

const typesPath = resolve(__dirname, '../dist/iframe-sdk-types.d.ts');
let dts = await readFile(typesPath, 'utf-8');

// 1. Collect all exported interface/type names
const typeNames = [...dts.matchAll(/^export (?:interface|type) (\w+)/gm)].map(m => m[1]);

// 2. Strip `export` keywords and sourcemap comments
dts = dts.replace(/^export /gm, '');
dts = dts.replace(/\/\/# sourceMappingURL=.*\n?/g, '');

// 3. Add `OkDoc` prefix to all type names (longest first to avoid partial matches)
typeNames.sort((a, b) => b.length - a.length);
for (const name of typeNames) {
    dts = dts.replace(new RegExp(`\\b${name}\\b`, 'g'), `OkDoc${name}`);
}

// 4. Wrap with header and `declare var`
const header = [
    '// ============================================================================',
    '// @okdoc/plugin-sdk — Iframe SDK Global Type Declarations (AUTO-GENERATED)',
    '//',
    '// DO NOT EDIT THIS FILE MANUALLY.',
    '// Generated by scripts/build-iframe-sdk.mjs from src/iframe-sdk-types.ts.',
    '// To update, edit that file and run:  npm run build:all',
    '//',
    '// Usage in iframe plugin projects:',
    '//   Copy this file into your project\'s src/ directory, OR reference it',
    '//   in tsconfig.json → "include": ["path/to/okdoc-iframe-sdk-global.d.ts"]',
    '// ============================================================================',
    '',
].join('\n');

const footer = '\ndeclare var OkDoc: OkDocIframeSDK;\n';

dts = header + dts + footer;

const outPath = resolve(__dirname, '../dist/okdoc-iframe-sdk-global.d.ts');
await writeFile(outPath, dts);
console.log('✅ okdoc-iframe-sdk-global.d.ts auto-generated from iframe-sdk-types.ts');
